  "phase": "plan",
  "decisions": [
    {
      "id": "d1",
      "decision": "Pin TZ=UTC via beforeAll(process.env.TZ='UTC') for deterministic locale-dependent output in formatTimestampLabel and formatBucketRangeLabel tests, allowing exact .toBe() assertions",
      "based_on": ["q1"],
      "alternatives_rejected": [
        "Structural/regex assertions — less precise, doesn't match repo style of exact .toBe()",
        "Setting TZ in vitest.config.ts env — would affect all tests globally, not just this file"
      ],
      "reversibility": "easy"
    },
    {
      "id": "d2",
      "decision": "Use @/ path aliases for imports, matching existing test convention — vitest.config.ts already has resolve.alias configured",
      "based_on": ["q2"],
      "alternatives_rejected": [
        "Relative imports — would work but breaks repo convention"
      ],
      "reversibility": "easy"
    },
    {
      "id": "d3",
      "decision": "Test formatSignedCurrency as composed behavior (no mocking of formatCurrency), matching repo convention of no mocks for pure utility functions",
      "based_on": ["q3"],
      "alternatives_rejected": [
        "Mock formatCurrency with vi.mock() — over-isolation for pure functions, breaks repo convention"
      ],
      "reversibility": "easy"
    },
    {
      "id": "d4",
      "decision": "Test getOutcomeColor fallback path with NaN and negative index inputs to validate the ?? defensive coding",
      "based_on": ["q4"],
      "alternatives_rejected": [
        "Skip edge cases — would leave defensive code untested"
      ],
      "reversibility": "easy"
    }
  ],
  "steps": [
    {
      "step": 1,
      "task": "Create test file at frontend/src/__tests__/chartUtils.test.ts with describe blocks for all 6 exported functions: getOutcomeColor, scaleNumber, buildLinePath, formatTimestampLabel, formatBucketRangeLabel, formatSignedCurrency. Pin TZ=UTC in beforeAll. Use @/ imports, exact .toBe() assertions, no mocks.",
      "depends_on": []
    },
    {
      "step": 2,
      "task": "Run vitest on the new test file to verify all tests pass. If TZ=UTC doesn't work in jsdom, fall back to structural assertions for locale-dependent functions.",
      "depends_on": [1]
    }
  ],
  "spawn_children": false,
  "children": []
}

{
  "phase": "research",
  "answers": [
    {
      "question_id": "q1",
      "answer": "Yes, tests should pin TZ=UTC to avoid locale-dependent failures. The CI config (.github/workflows/ci.yml) does NOT set any TZ or locale env vars. formatTimestampLabel and formatBucketRangeLabel use toLocaleDateString/toLocaleTimeString with [] as the locale argument (runtime default), so output will differ between CI (ubuntu-latest, likely UTC) and developer machines (various timezones). The simplest fix is to set TZ=UTC either in the test file via beforeAll or as a vitest env variable. An alternative is structural assertions (regex matching for month/day patterns), but pinning TZ=UTC is more robust and lets us assert exact strings, which matches the existing test style in format.test.ts (exact .toBe() assertions, not regex).",
      "confidence": 0.95,
      "evidence": [
        "frontend/src/features/analytics/chartUtils.ts:41-44",
        "frontend/src/features/analytics/chartUtils.ts:47",
        "frontend/src/features/analytics/chartUtils.ts:61-63",
        ".github/workflows/ci.yml:41-43",
        "frontend/src/__tests__/format.test.ts:5-7"
      ],
      "uncertainty": "Whether setting process.env.TZ in a vitest beforeAll reliably affects toLocaleTimeString in the jsdom environment. Node.js respects TZ for Intl, but jsdom may have edge cases. If it doesn't work, falling back to structural assertions is the backup."
    },
    {
      "question_id": "q2",
      "answer": "A vitest.config.ts ALREADY EXISTS at frontend/vitest.config.ts with the @ alias configured (resolve.alias: { '@': path.resolve(__dirname, './src') }). The question's premise is partially outdated — there IS a vitest config, separate from vite.config.ts. The test file should use @/ imports, exactly as format.test.ts and other existing tests do. No configuration changes are needed.",
      "confidence": 1.0,
      "evidence": [
        "frontend/vitest.config.ts:7-10",
        "frontend/src/__tests__/format.test.ts:2"
      ],
      "uncertainty": "None — vitest.config.ts exists and is confirmed working with existing @/ imports in test files."
    },
    {
      "question_id": "q3",
      "answer": "Test the composed behavior directly, without mocking formatCurrency. This matches the existing repo convention: format.test.ts tests formatCurrency with exact value assertions (toBe) and no mocks. formatSignedCurrency is a thin wrapper that adds a '+' prefix for positive values and delegates to formatCurrency. Testing the composed output (e.g., expect(formatSignedCurrency(1500)).toBe('+1.5K')) is clearer, simpler, and consistent with the codebase style. The only mock usage in the repo is for external dependencies (fetch, API client modules), never for pure utility functions.",
      "confidence": 0.98,
      "evidence": [
        "frontend/src/__tests__/format.test.ts:10-14",
        "frontend/src/features/analytics/chartUtils.ts:67-70",
        "frontend/src/__tests__/api-client.test.ts:1-2"
      ],
      "uncertainty": "None — the convention is clear and unambiguous."
    },
    {
      "question_id": "q4",
      "answer": "Yes, tests should verify the fallback path. With noUncheckedIndexedAccess: true in tsconfig.json, the ?? '#818cf8' fallback is there for a reason. The fallback triggers when OUTCOME_COLORS[index % OUTCOME_COLORS.length] returns undefined, which happens in two practical cases: (1) NaN input — NaN % 6 = NaN, and OUTCOME_COLORS[NaN] = undefined. (2) Negative indices — (-1) % 6 = -1 in JavaScript, and OUTCOME_COLORS[-1] = undefined. Both are realistic edge cases (e.g., index from an empty array's length-1, or a calculation that produces NaN). Testing these validates the defensive coding and documents the expected behavior for consumers.",
      "confidence": 0.95,
      "evidence": [
        "frontend/src/features/analytics/chartUtils.ts:13-15",
        "frontend/src/features/analytics/chartUtils.ts:4-11",
        "frontend/tsconfig.json:18"
      ],
      "uncertainty": "Whether negative index inputs are realistic in the actual call sites. But testing them is cheap and documents behavior regardless."
    }
  ],
  "assumption_checks": [
    {
      "assumption_id": "a1",
      "verdict": "CORRECT",
      "confidence": 1.0,
      "impact": "No action needed. vitest.config.ts exists at frontend/vitest.config.ts with resolve.alias configured for @/. All existing tests use @/ imports successfully."
    },
    {
      "assumption_id": "a2",
      "verdict": "CORRECT",
      "confidence": 1.0,
      "impact": "Test file should use: import { describe, it, expect } from 'vitest'; use @/ path aliases; concise one-liner assertions with .toBe(); describe blocks per function. Matches format.test.ts exactly."
    },
    {
      "assumption_id": "a3",
      "verdict": "UNCERTAIN",
      "confidence": 0.7,
      "impact": "Structural assertions are a valid fallback, but pinning TZ=UTC is preferred because it matches the repo's style of exact .toBe() assertions. Need to verify that process.env.TZ works in jsdom/vitest. If not, fall back to structural assertions (regex, .toContain())."
    },
    {
      "assumption_id": "a4",
      "verdict": "CORRECT",
      "confidence": 1.0,
      "impact": "No mocking needed. All functions are pure (formatSignedCurrency composes formatCurrency which is also pure). The repo convention is to not mock pure utility functions."
    },
    {
      "assumption_id": "a5",
      "verdict": "CORRECT",
      "confidence": 1.0,
      "impact": "Test file goes at frontend/src/__tests__/chartUtils.test.ts. The __tests__/ directory has a flat structure with all test files at the same level."
    },
    {
      "assumption_id": "a6",
      "verdict": "CORRECT",
      "confidence": 1.0,
      "impact": "OUTCOME_COLORS has exactly 6 entries (lines 4-11). Index 6 should wrap to index 0's color (#818cf8). Test indices 0-5 for distinct colors and index 6 for wrap-around."
    }
  ],
  "spawn_children": false,
  "children": []
}

{
  "phase": "question",
  "questions": [
    {
      "id": "q1",
      "question": "Should formatTimestampLabel and formatBucketRangeLabel tests pin a specific timezone (e.g. via TZ env var) to avoid locale-dependent failures in CI vs local dev?",
      "category": "design",
      "why_it_matters": "These functions use toLocaleDateString/toLocaleTimeString which produce different output depending on the runtime's timezone and locale. Tests will be flaky without a deterministic approach."
    },
    {
      "id": "q2",
      "question": "No vitest.config.ts exists — the vite.config.ts has the @ path alias but no test block. Should the test file import via relative paths or should we add a test config with resolve.alias?",
      "category": "codebase",
      "why_it_matters": "The existing tests use @/ imports (e.g. format.test.ts imports from @/lib/utils/format). If vitest resolves these through vite.config.ts automatically, we can do the same; otherwise the new test will fail to resolve imports."
    },
    {
      "id": "q3",
      "question": "formatSignedCurrency delegates to formatCurrency from @/lib/utils/format. Should we mock formatCurrency to isolate the unit, or test the composed behavior directly (matching existing test style)?",
      "category": "design",
      "why_it_matters": "The existing format.test.ts tests formatCurrency directly without mocks. Using the same approach for formatSignedCurrency means tests double-cover formatCurrency logic, but matches the repo convention of no mocks for pure functions."
    },
    {
      "id": "q4",
      "question": "getOutcomeColor uses nullish coalescing (?? '#818cf8') after index-modulo lookup. With noUncheckedIndexedAccess enabled in tsconfig, the return type includes undefined — should tests specifically verify the fallback path (negative indices, NaN)?",
      "category": "requirements",
      "why_it_matters": "The ?? fallback only activates if OUTCOME_COLORS[index % length] returns undefined, which in practice only happens with NaN % length = NaN. Testing this edge case validates the defensive coding."
    }
  ],
  "assumptions": [
    {
      "id": "a1",
      "assumption": "Vitest resolves the @/ path alias from vite.config.ts automatically (since existing tests like format.test.ts already use @/ imports successfully)",
      "confidence": 0.95,
      "if_wrong": "Need to add a vitest.config.ts with resolve.alias or use relative imports in the test file"
    },
    {
      "id": "a2",
      "assumption": "Tests should follow the existing convention: vitest imports (describe/it/expect), @/ path aliases, concise one-liner assertions where possible, describe blocks per function",
      "confidence": 0.98,
      "if_wrong": "Would need to restructure tests to match a different convention"
    },
    {
      "id": "a3",
      "assumption": "For locale-dependent functions (formatTimestampLabel, formatBucketRangeLabel), we can test structural properties (contains expected substrings, correct format pattern) rather than exact string matches to avoid timezone/locale flakiness",
      "confidence": 0.85,
      "if_wrong": "May need to set TZ=UTC and mock locale, or use regex-based assertions"
    },
    {
      "id": "a4",
      "assumption": "No mocking is needed — all six functions are pure (or locale-dependent but deterministic for a given environment) and have no external dependencies beyond formatCurrency which is itself pure",
      "confidence": 0.95,
      "if_wrong": "Would need vi.mock() for formatCurrency in formatSignedCurrency tests"
    },
    {
      "id": "a5",
      "assumption": "The test file should be placed at frontend/src/__tests__/chartUtils.test.ts matching the existing flat test directory structure",
      "confidence": 0.99,
      "if_wrong": "Task description explicitly specifies this path"
    },
    {
      "id": "a6",
      "assumption": "OUTCOME_COLORS array has 6 entries, so index wrapping tests should verify indices 0-5 return distinct colors and index 6 wraps to index 0's color",
      "confidence": 1.0,
      "if_wrong": "Would need to adjust test expectations if array size differs"
    }
  ],
  "spawn_children": false,
  "children": []
}

